#!/usr/bin/env bash
# Generate the pg-formats demo artifacts.
#
# Produces seven files under demos/pg-formats/output/:
#   modern_graph.json              -- Hydra-PG JSON of the Modern graph (copied from HydraPop)
#   schema.json                    -- Hydra-PG JSON of the Modern graph schema (copied from HydraPop)
#   modern_graph.graphson.jsonl    -- GraphSON 3.0, generated by Hydra (Haskell)
#   Graph.schema.json              -- JSON Schema for hydra.pg.model.Graph, generated by Hydra (Haskell)
#   GraphSchema.schema.json        -- JSON Schema for hydra.pg.model.GraphSchema, generated by Hydra (Haskell)
#   GraphsonVertex.schema.json     -- JSON Schema for hydra.pg.graphson.syntax.Vertex, generated by Hydra (Haskell)
#   pg-model.proto                 -- Protobuf v3 definitions for hydra.pg.model, generated by Hydra (Haskell)
#   Graph.avsc                     -- Avro schema for hydra.pg.model.Graph, generated by Hydra (Haskell)
#   GraphSchema.avsc               -- Avro schema for hydra.pg.model.GraphSchema, generated by Hydra (Haskell)
#
# The first two are produced by HydraPop's Java GenerateExampleData and tracked
# in HydraPop. The last seven are produced by Hydra-Haskell via
# Hydra.Demos.PgFormats.Demo.generatePgFormats.

set -euo pipefail

# Resolve paths relative to this script.
script_dir="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
demo_dir="$(cd "$script_dir/.." && pwd)"
worktree_root="$(cd "$demo_dir/../.." && pwd)"
output_dir="$demo_dir/output"

mkdir -p "$output_dir"

# 1+2. Copy Hydra-PG JSON artifacts from HydraPop, if available.
hydrapop_json="$worktree_root/../../../HydraPop/src/gen-main/json"
if [ -d "$hydrapop_json" ]; then
  cp "$hydrapop_json/modern_graph.json" "$output_dir/modern_graph.json"
  cp "$hydrapop_json/schema.json"       "$output_dir/schema.json"
  echo "Copied modern_graph.json and schema.json from $hydrapop_json"
else
  echo "WARNING: HydraPop sources not found at $hydrapop_json"
  echo "         modern_graph.json and schema.json will not be refreshed."
fi

# 3+4+5+6. Run Hydra-Haskell driver.
# Note: pass the GHCi script via -ghci-script (not stdin); stdin redirection
# does not reach ghci because `stack ghci` consumes stdin for its own
# disambiguation prompts.
cd "$worktree_root/heads/haskell"
echo "Running Hydra-Haskell GraphSON + JSON Schema generation..."
stack ghci --main-is hydra:lib \
  --ghci-options='+RTS -K256M -A32M -RTS' \
  --ghci-options "-ghci-script $demo_dir/bin/generate.ghci"

echo ""
echo "Done. Artifacts:"
ls -la "$output_dir"
